/**
 * HotkeysSettings - Displays current keyboard shortcuts
 *
 * Shows a table of registered Chrome extension commands with their
 * keyboard shortcuts. Read-only reference with link to Chrome's
 * native shortcut editor.
 */

import React, { useEffect, useState } from 'react'

interface ChromeCommand {
  name?: string
  description?: string
  shortcut?: string
}

export const HotkeysSettings: React.FC = () => {
  const [commands, setCommands] = useState<ChromeCommand[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (typeof chrome !== 'undefined' && chrome.commands) {
      chrome.commands.getAll((cmds: ChromeCommand[]) => {
        setCommands(cmds || [])
        setLoading(false)
      })
    } else {
      // Dev/fallback: show manifest commands
      setCommands([
        { name: 'toggle-font', description: 'Toggle dyslexia font', shortcut: 'Ctrl+Shift+F' },
        { name: 'read-aloud', description: 'Read selected text aloud', shortcut: 'Ctrl+Shift+R' },
        { name: 'toggle-bionic-reading', description: 'Toggle bionic reading mode', shortcut: 'Ctrl+Shift+B' },
        { name: 'toggle-reading-ruler', description: 'Toggle reading ruler', shortcut: 'Ctrl+Shift+L' }
      ])
      setLoading(false)
    }
  }, [])

  if (loading) {
    return <div className="text-lg text-gray-500">Loading shortcuts...</div>
  }

  return (
    <div className="space-y-8">
      <div>
        <h2 className="mb-2 text-2xl font-bold text-gray-900">Keyboard Shortcuts</h2>
        <p className="text-lg text-gray-500">View and manage your keyboard shortcuts for quick access to features.</p>
      </div>

      <div className="overflow-hidden rounded-lg border border-gray-200">
        <table className="w-full text-left text-lg">
          <thead>
            <tr className="border-b border-gray-200 bg-gray-50">
              <th className="px-6 py-4 font-semibold text-gray-700">Action</th>
              <th className="px-6 py-4 font-semibold text-gray-700">Keyboard Shortcut</th>
            </tr>
          </thead>
          <tbody>
            {commands.map((cmd) => (
              <tr key={cmd.name || Math.random()} className="border-b border-gray-100 last:border-0">
                <td className="px-6 py-4 text-gray-800">
                  {cmd.description || cmd.name || 'Unknown'}
                </td>
                <td className="px-6 py-4">
                  {cmd.shortcut ? (
                    <kbd className="inline-block rounded-md border border-gray-300 bg-gray-100 px-3 py-1 font-mono text-base text-gray-700 shadow-sm">
                      {cmd.shortcut}
                    </kbd>
                  ) : (
                    <span className="inline-block rounded-md bg-gray-100 px-3 py-1 text-base text-gray-400">
                      Not set
                    </span>
                  )}
                </td>
              </tr>
            ))}
            {commands.length === 0 && (
              <tr>
                <td colSpan={2} className="px-6 py-8 text-center text-gray-400 text-lg">
                  No keyboard shortcuts registered
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="rounded-lg bg-blue-50 p-6">
        <p className="text-lg text-blue-800">
          <span className="font-semibold">Change shortcuts:</span> Open{' '}
          <code className="rounded bg-blue-100 px-2 py-1 text-base font-mono">
            chrome://extensions/shortcuts
          </code>{' '}
          in your browser to customize keyboard shortcuts for this extension.
        </p>
      </div>
    </div>
  )
}
